const oppStages = $('Opp Stage Counts').first().json.stage ? $('Opp Stage Counts').all().map(i => i.json).filter(i => i.stage) : [];
const captureRaw = $('Capture Plan Stages').all().map(i => i.json).filter(i => i.stage);
const seen = new Set();
const captureStages = captureRaw.filter(r => { if (seen.has(r.stage)) return false; seen.add(r.stage); return true; });
const topRaw = $('Top Opps').all().map(i => i.json).filter(i => i.opp_title);
const seenT = new Set();
const topOpps = topRaw.filter(r => { var k = r.opp_title+r.tcv; if (seenT.has(k)) return false; seenT.add(k); return true; });

const totalOpps = oppStages.reduce((s,r) => s + parseInt(r.count||0), 0);
const totalValue = oppStages.reduce((s,r) => s + parseFloat(r.value_m||0), 0);
const totalCapture = captureStages.reduce((s,r) => s + parseInt(r.count||0), 0);
const totalTCV = captureStages.reduce((s,r) => s + parseFloat(r.tcv_m||0), 0);
const totalAlloc = captureStages.reduce((s,r) => s + parseFloat(r.alloc_m||0), 0);

return [{ json: {
  summary: { totalOpps, totalValue: Math.round(totalValue*10)/10, totalCapture, totalTCV: Math.round(totalTCV*100)/100, totalAlloc: Math.round(totalAlloc*100)/100 },
  oppStages, captureStages, topOpps,
  generatedAt: new Date().toISOString()
} }];
